    // --- Device-based resolution ---

    #[test]
    fn device_cpu() {
        let gpu = GpuCapabilities::new(true, true);
        let r = resolve_backend("cpu", "", ModelType::Embedding, &gpu).unwrap();
        assert_eq!(r.backend, BackendKind::Cpu);
